mod.talkaction:
domodlib('castle_config') domodlib('castle_lib')
function onSay(cid, words, param) if getStorage(castleCfg.storage.event) ~= 1 then doSetStorage(castleCfg.storage.event, 1) doCleanCastleFighters() doStartCountingCastleEvent(0)
for _, pid in ipairs(getPlayersOnline()) do if getCreatureStorage(pid, castleCfg.storage.winner) > 0 then doCreatureSetStorage(pid, castleCfg.storage.winner, -1) doTeleportThing(pid, getTownTemplePosition(getPlayerTown(pid)), true) end end else doPlayerSendCancel(cid, 'You can not do it if "castle war" is enabled yet.') end return true end

mod.globalevent:
domodlib('castle_config') domodlib('castle_lib')
local daysOpen = {}
for k, v in pairs(castleCfg.days) do table.insert(daysOpen, k) end
function onThink(interval) if isInArray(daysOpen, os.date('%A')) then if isInArray(castleCfg.days[os.date('%A')], os.date('%X', os.time())) then if getStorage(castleCfg.storage.event) ~= 1 then doSetStorage(castleCfg.storage.event, 1) doCleanCastleFighters() doStartCountingCastleEvent(0)
for _, pid in ipairs(getPlayersOnline()) do if getCreatureStorage(pid, castleCfg.storage.winner) > 0 then doCreatureSetStorage(pid, castleCfg.storage.winner, -1) doTeleportThing(pid, getTownTemplePosition(getPlayerTown(pid)), true) end end end end end
if getStorage(castleCfg.storage.event) == 1 then if getStorage(castleCfg.storage.time) == os.time() then doCloseCastleWar() end end return true end
